/** Check if a dot-notation path exists as keys in the nested object */
export function hasPath(obj: unknown, path: string): boolean {
  const keys = path.split(".");
  let current: unknown = obj;
  for (const key of keys) {
    if (current == null || typeof current !== "object") return false;
    if (!(key in (current as Record<string, unknown>))) return false;
    current = (current as Record<string, unknown>)[key];
  }
  return true;
}

/** Deep get a value from an object using dot-notation path */
export function getIn(obj: unknown, path: string): unknown {
  const keys = path.split(".");
  let current: unknown = obj;
  for (const key of keys) {
    if (current == null) return undefined;
    current = (current as Record<string, unknown>)[key];
  }
  return current;
}

/** Immutable deep delete of a property at a dot-path with structural sharing */
export function deleteIn<T>(obj: T, path: string): T {
  const keys = path.split(".");
  if (keys.length === 1) {
    const { [keys[0]!]: _, ...rest } = obj as Record<string, unknown>;
    return rest as T;
  }
  const parentPath = keys.slice(0, -1).join(".");
  const lastKey = keys[keys.length - 1]!;
  const parent = getIn(obj, parentPath);
  if (parent == null || typeof parent !== "object") return obj;
  const { [lastKey]: _, ...rest } = parent as Record<string, unknown>;
  return setIn(obj, parentPath, rest);
}

/** Deep get a value expected to be an array (returns [] if missing or not array) */
export function getInArray(obj: unknown, path: string): unknown[] {
  const val = getIn(obj, path);
  return Array.isArray(val) ? val : [];
}

/** Immutable deep set with structural sharing */
export function setIn<T>(obj: T, path: string, value: unknown): T {
  const keys = path.split(".");
  if (keys.length === 0) return value as T;
  return setAtKeys(obj, keys, 0, value) as T;
}

function setAtKeys(
  obj: unknown,
  keys: string[],
  i: number,
  value: unknown,
): unknown {
  if (i === keys.length) return value;
  const key = keys[i]!;
  const current =
    obj != null ? (obj as Record<string, unknown>)[key] : undefined;
  const next = setAtKeys(current, keys, i + 1, value);
  if (Array.isArray(obj)) {
    const copy = obj.slice();
    copy[Number(key)] = next;
    return copy;
  }
  return { ...(obj as Record<string, unknown>), [key]: next };
}
